import{_ as l,o as t,c as i,ag as r}from"./chunks/framework.Cqf6AMW8.js";const m=JSON.parse('{"title":"STM32 外设应用","description":"STM32 外设应用，包括OLED、旋转编码器、舵机和电机的配置与使用。","frontmatter":{"title":"STM32 外设应用","description":"STM32 外设应用，包括OLED、旋转编码器、舵机和电机的配置与使用。","date":"2026-04-21T00:00:00.000Z","tags":["STM32","OLED","旋转编码器","舵机","电机"],"sidebar":"auto"},"headers":[],"relativePath":"docs/hardware/stm32/stm32-4-OLED 旋转编码器 舵机 电机.md","filePath":"docs/hardware/stm32/stm32-4-OLED 旋转编码器 舵机 电机.md","lastUpdated":1776715536000}'),e={name:"docs/hardware/stm32/stm32-4-OLED 旋转编码器 舵机 电机.md"};function o(s,a,d,n,h,u){return t(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="stm32" tabindex="-1">STM32 <a class="header-anchor" href="#stm32" aria-label="Permalink to &quot;STM32&quot;">​</a></h1><p>======================================================</p><h2 id="oled、旋转编码器、舵机、电机" tabindex="-1">OLED、旋转编码器、舵机、电机 <a class="header-anchor" href="#oled、旋转编码器、舵机、电机" aria-label="Permalink to &quot;OLED、旋转编码器、舵机、电机&quot;">​</a></h2><h2 id="oled配置" tabindex="-1">OLED配置 <a class="header-anchor" href="#oled配置" aria-label="Permalink to &quot;OLED配置&quot;">​</a></h2><h3 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h3><ul><li><strong>供电</strong>：3.3V</li><li><strong>通信协议</strong>：I2C</li><li><strong>引脚定义</strong>： <ul><li>GND：接地</li><li>3.3V：电源</li><li>SCL：I2C时钟同步线</li><li>SDA：I2C数据同步线</li></ul></li></ul><h3 id="配置步骤" tabindex="-1">配置步骤 <a class="header-anchor" href="#配置步骤" aria-label="Permalink to &quot;配置步骤&quot;">​</a></h3><ol><li>开启I2C时钟</li><li>配置GPIO为开漏输出</li><li>初始化I2C</li><li>发送初始化命令</li><li>实现显示函数</li></ol><h2 id="旋转编码器" tabindex="-1">旋转编码器 <a class="header-anchor" href="#旋转编码器" aria-label="Permalink to &quot;旋转编码器&quot;">​</a></h2><h3 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h3><ul><li><strong>用途</strong>：测量旋转角度、速度和方向</li><li><strong>角度测量</strong>：根据A/B两相的边沿变化次数</li><li><strong>速度测量</strong>：根据边沿变化频率</li><li><strong>方向判断</strong>：根据A/B两相的相位差</li></ul><h3 id="配置步骤-1" tabindex="-1">配置步骤 <a class="header-anchor" href="#配置步骤-1" aria-label="Permalink to &quot;配置步骤&quot;">​</a></h3><ol><li>配置GPIO为输入模式</li><li>配置外部中断</li><li>在中断处理函数中判断旋转方向</li><li>实现计数和速度测量</li></ol><h2 id="舵机" tabindex="-1">舵机 <a class="header-anchor" href="#舵机" aria-label="Permalink to &quot;舵机&quot;">​</a></h2><h3 id="工作原理-1" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理-1" aria-label="Permalink to &quot;工作原理&quot;">​</a></h3><ul><li><strong>控制方式</strong>：通过PWM占空比控制输出角度</li><li><strong>特性</strong>： <ul><li>响应时间：0.12s/60°</li><li>角度定位：每个角度都是固定位置</li></ul></li><li><strong>PWM参数</strong>： <ul><li>周期：20ms</li><li>高电平：0.5~2.5ms</li></ul></li></ul><h3 id="角度对照表" tabindex="-1">角度对照表 <a class="header-anchor" href="#角度对照表" aria-label="Permalink to &quot;角度对照表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>脉冲宽度</th><th>输出角度</th></tr></thead><tbody><tr><td>0.5ms</td><td>-90°</td></tr><tr><td>1ms</td><td>-45°</td></tr><tr><td>1.5ms</td><td>0°</td></tr><tr><td>2ms</td><td>45°</td></tr><tr><td>2.5ms</td><td>90°</td></tr></tbody></table><h3 id="配置步骤-2" tabindex="-1">配置步骤 <a class="header-anchor" href="#配置步骤-2" aria-label="Permalink to &quot;配置步骤&quot;">​</a></h3><ol><li>配置TIM定时器</li><li>设置PWM模式</li><li>计算并设置对应角度的占空比</li><li>使能PWM输出</li></ol><h2 id="电机" tabindex="-1">电机 <a class="header-anchor" href="#电机" aria-label="Permalink to &quot;电机&quot;">​</a></h2><h3 id="工作原理-2" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理-2" aria-label="Permalink to &quot;工作原理&quot;">​</a></h3><ul><li><strong>控制方式</strong>：通过改变电源极性控制旋转方向</li><li><strong>正转</strong>：电极正接</li><li><strong>反转</strong>：电极反接</li></ul><h3 id="配置步骤-3" tabindex="-1">配置步骤 <a class="header-anchor" href="#配置步骤-3" aria-label="Permalink to &quot;配置步骤&quot;">​</a></h3><ol><li>配置GPIO为输出模式</li><li>使用晶体管或电机驱动芯片</li><li>实现正反转控制函数</li><li>可配合PWM实现速度控制</li></ol>',25)])])}const b=l(e,[["render",o]]);expor